const body = $input.first().json.body || $input.first().json;

// ── Required field guards ─────────────────────────────────────
if (!body.employeeName || body.employeeName.trim() === '') {
  throw new Error('Missing required field: employeeName');
}
if (!body.fileUrl && !body.filename) {
  throw new Error('Provide either fileUrl (remote document) or filename (binary upload).');
}

// ── Name normalisation (Title Case, strip special chars) ──────
const normaliseName = (raw) => {
  return raw
    .trim()
    .replace(/[^a-zA-Z\s\-']/g, '')
    .replace(/\s+/g, ' ')
    .split(' ')
    .map(w => w.charAt(0).toUpperCase() + w.slice(1).toLowerCase())
    .join(' ');
};
const employeeName = normaliseName(body.employeeName);
const nameParts = employeeName.split(' ');
const lastName = nameParts[nameParts.length - 1];
const firstName = nameParts[0];

// ── Employee ID ────────────────────────────────────────────────
const employeeId = (body.employeeId || '').toUpperCase().replace(/[^A-Z0-9\-]/g, '') || `EMP-${Date.now()}`;

// ── Contract type slug ────────────────────────────────────────
const contractType = body.contractType || 'Employment Contract';
const contractTypeSlug = contractType.replace(/\s+/g, '-').replace(/[^a-zA-Z0-9\-]/g, '').toUpperCase();

// ── Date handling ─────────────────────────────────────────────
const effectiveDate = body.effectiveDate || new Date().toISOString().split('T')[0];
const filedAt = new Date().toISOString();
const yearFolder = effectiveDate.split('-')[0];

// ── Filename — structured for audit trail ─────────────────────
const originalFilename = body.filename || body.fileUrl?.split('?')[0].split('/').pop() || 'document.pdf';
const ext = originalFilename.split('.').pop()?.toLowerCase() || 'pdf';
const allowedExts = ['pdf', 'jpg', 'jpeg', 'png', 'docx', 'tiff'];
if (!allowedExts.includes(ext)) {
  throw new Error(`File type .${ext} not allowed. Accepted: ${allowedExts.join(', ')}`);
}
const structuredFilename = `${employeeId}_${lastName.toUpperCase()}_${contractTypeSlug}_${effectiveDate}.${ext}`;

// ── MIME type map ─────────────────────────────────────────────
const mimeMap = {
  pdf: 'application/pdf',
  jpg: 'image/jpeg', jpeg: 'image/jpeg',
  png: 'image/png',
  docx: 'application/vnd.openxmlformats-officedocument.wordprocessingml.document',
  tiff: 'image/tiff'
};
const mimeType = mimeMap[ext] || 'application/octet-stream';

// ── Drive folder path ─────────────────────────────────────────
const department = body.department || 'General';
const driveFolderPath = `HR/Contracts/${yearFolder}/${department}/${employeeName}`;

return [{
  json: {
    // Source
    fileUrl: body.fileUrl || null,
    originalFilename,
    structuredFilename,
    mimeType,
    ext,
    // Employee
    employeeName,
    firstName,
    lastName,
    employeeId,
    employeeEmail: body.employeeEmail || '',
    department,
    // Contract
    contractType,
    contractTypeSlug,
    effectiveDate,
    // Drive
    driveFolderPath,
    yearFolder,
    rootFolderId: $vars.GDRIVE_ROOT_FOLDER_ID || 'root',
    // Flags
    notifyEmployee: body.notifyEmployee !== false,
    filedBy: body.filedBy || 'HR System',
    filedAt
  }
}];

const uploadResp = $input.first().json;
const meta = $('Validate & Enrich Payload').first().json;

const cdnUrl =
  uploadResp.url ||
  uploadResp.link ||
  uploadResp.data?.url ||
  uploadResp.file?.url ||
  uploadResp.shortUrl;

if (!cdnUrl) {
  throw new Error('Upload to URL returned no public URL. Response: ' + JSON.stringify(uploadResp));
}

return [{
  json: {
    ...meta,
    cdnUrl: cdnUrl.replace(/^http:\/\//, 'https://'),
    uploadId: uploadResp.id || uploadResp.data?.id || null,
    fileSizeBytes: uploadResp.size || uploadResp.data?.size || null
  }
}];

// Decide whether to create a new folder or use the existing one
const searchResult = $input.first().json;
const meta = $('Extract CDN URL').first().json;

// Google Drive search returns items array
const existingFolder = searchResult.files?.[0] || searchResult.items?.[0] || null;
const folderId = existingFolder?.id || null;

return [{
  json: {
    ...meta,
    existingFolderId: folderId,
    needsNewFolder: !folderId
  }
}];

// Merge the folder ID from either path (new or existing)
const input = $input.first().json;
const meta = $('Resolve Folder ID').first().json;

// If we just created a folder, the response has the new folder's id
const targetFolderId =
  input.id ||               // newly created folder
  meta.existingFolderId;    // pre-existing folder

if (!targetFolderId) {
  throw new Error('Could not resolve a Google Drive folder ID for upload.');
}

return [{
  json: {
    ...meta,
    targetFolderId
  }
}];

const airtableResp = $input.first().json;
const meta = $('Merge Folder ID').first().json;
const driveResp = $('Drive - Upload Document').first().json;

// Build Drive shareable URL from file ID
const driveFileId = driveResp.id;
const driveUrl = driveFileId
  ? `https://drive.google.com/file/d/${driveFileId}/view`
  : null;

const existingRecord = airtableResp.records?.[0] || null;

return [{
  json: {
    ...meta,
    driveFileId,
    driveUrl,
    airtableRecordId: existingRecord?.id || null,
    airtableRecordExists: !!existingRecord
  }
}];

// Normalise output from both Airtable branches
const airtableResp = $input.first().json;
const meta = $('Prepare Airtable Update').first().json;

const airtableRecordId = airtableResp.id || meta.airtableRecordId;

return [{
  json: {
    ...meta,
    airtableRecordId,
    airtableUpdated: true
  }
}];

const emailResp = $input.first().json;
const data = $('Merge Airtable Result').first().json;

return [{
  json: {
    success: true,
    message: `Contract for ${data.employeeName} successfully archived.`,
    // Core identifiers
    employeeId: data.employeeId,
    employeeName: data.employeeName,
    department: data.department,
    // Document
    structuredFilename: data.structuredFilename,
    contractType: data.contractType,
    effectiveDate: data.effectiveDate,
    // Storage
    driveFileId: data.driveFileId,
    driveUrl: data.driveUrl,
    driveFolderPath: data.driveFolderPath,
    cdnBackupUrl: data.cdnUrl,
    // Airtable
    airtableRecordId: data.airtableRecordId,
    // Audit trail
    auditTrail: {
      filedBy: data.filedBy,
      filedAt: data.filedAt,
      uploadId: data.uploadId,
      fileSizeBytes: data.fileSizeBytes
    }
  }
}];

const err = $input.first();
const msg = err.json?.message || err.error?.message || err.json?.error || 'Unexpected error in document archiving workflow';
console.error('[HR Archive] Error:', msg);
return [{ json: { success: false, error: msg, timestamp: new Date().toISOString() } }];
